SELECT
p.place_id,
p.title,
p.addr1,
p.first_image1,
p.category_code1,
p.category_code2,
COUNT(pl.user_id) AS like_count,
EXISTS (
SELECT 1 FROM place_likes
WHERE place_id = p.place_id AND user_id = #{userId}
) AS liked
FROM places p
LEFT JOIN place_likes pl ON p.place_id = pl.place_id


		AND p.area_code = #{req.areaCode}


		AND p.district_code = #{req.districtCode}


		AND p.category_code1 = #{req.category1}


		AND p.category_code2 = #{req.category2}


		AND p.title LIKE CONCAT('%', #{req.keyword}, '%')

	AND p.addr1 IS NOT NULL AND p.addr1 != ''

GROUP BY p.place_id
ORDER BY like_count DESC, p.place_id
LIMIT #{req.limitSize}
OFFSET #{req.offset}

SELECT place_id, content_id, title, addr1, addr2,
       latitude, longitude, first_image1, first_image2,
       area_code, district_code, category_code1, category_code2,
       zipcode, tel, overview,
       EXISTS (
		   SELECT 1 FROM place_likes
	       WHERE place_id = #{placeId} AND user_id = #{userId}
	   ) AS liked
FROM places
WHERE place_id = #{placeId}

SELECT COUNT(*) > 0
FROM place_likes
WHERE place_id = #{placeId} AND user_id = #{userId}

SELECT COUNT(*)
FROM place_likes
WHERE place_id = #{placeId}
